// Extract and normalize email metadata
const item = $input.item.json;

const senderName = item.From ? item.From.split('<')[0].trim().replace(/"/g, '') : 'Unknown';
const senderEmailMatch = (item.From || '').match(/<(.+)>/);
const senderEmail = senderEmailMatch ? senderEmailMatch[1] : (item.From || '');

return {
  json: {
    sender_name: senderName,
    sender_email: senderEmail,
    email_subject: item.Subject || '(no subject)',
    email_body: item.text || item.snippet || '',
    received_at: item.Date || new Date().toISOString()
  }
};

const item = $input.item.json;

const subject = (item.email_subject || '').toLowerCase();
const body = (item.email_body || '').toLowerCase();
const text = subject + ' ' + body;

// Category detection
let category = 'General Inquiry';
if (/refund|money back|reimburse/.test(text)) category = 'Refund Request';
else if (/bill|invoice|payment|charge|subscription cost/.test(text)) category = 'Billing';
else if (/bug|error|crash|not working|broken|glitch/.test(text)) category = 'Bug Report';
else if (/password|login|access|account locked|can't sign in/.test(text)) category = 'Account Access';
else if (/feature|suggestion|would be nice|request.*add/.test(text)) category = 'Feature Request';
else if (/buy|purchase|pricing|demo|quote|upgrade plan/.test(text)) category = 'Sales Inquiry';
else if (/help|support|issue|problem|trouble/.test(text)) category = 'Technical Support';

// Priority detection
let priority = 'Medium';
if (/urgent|asap|critical|immediately|emergency|down/.test(text)) priority = 'Critical';
else if (/soon|important|high priority/.test(text)) priority = 'High';
else if (/whenever|no rush|low priority/.test(text)) priority = 'Low';

// Sentiment detection
let sentiment = 'Neutral';
if (/angry|frustrated|terrible|worst|unacceptable|disappointed|furious/.test(text)) sentiment = 'Negative';
else if (/thank|great|love|appreciate|excellent|happy/.test(text)) sentiment = 'Positive';

// Department mapping
const departmentMap = {
  'Billing': 'Finance',
  'Refund Request': 'Finance',
  'Sales Inquiry': 'Sales',
  'Feature Request': 'Product Team',
  'Bug Report': 'Technical Support',
  'Account Access': 'Customer Success',
  'Technical Support': 'Technical Support',
  'General Inquiry': 'Customer Success'
};

// Simple tag extraction
const tags = [];
if (/mobile|app/.test(text)) tags.push('mobile');
if (/web|website|browser/.test(text)) tags.push('web');
if (/payment|card/.test(text)) tags.push('payment');
if (tags.length === 0) tags.push('general');

return {
  json: {
    customer_name: item.sender_name || 'Unknown',
    company: item.company || '',
    sender_email: item.sender_email || '',
    issue_summary: (item.email_subject || 'No subject').substring(0, 100),
    detailed_description: item.email_body || '',
    category: category,
    priority: priority,
    sentiment: sentiment,
    product_service: '',
    suggested_department: departmentMap[category],
    suggested_tags: tags,
    confidence_score: 0.75,
    received_at: item.received_at || new Date().toISOString()
  }
};
